// FVE Logger - rotace souboru (odstran zaznamy starsi 3 dny)
var fs = require('fs');
var logFile = "/homeassistant/fve_log.jsonl";
var cutoff = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString();

try {
    var existing = "";
    try { existing = fs.readFileSync(logFile, "utf8"); } catch(e) {}
    var lines = existing.split("\n").filter(function(l) {
        if (!l.trim()) return false;
        try { return JSON.parse(l).ts >= cutoff; } catch(e) { return false; }
    });
    if (lines.length > 0) {
        fs.writeFileSync(logFile, lines.join("\n") + "\n", "utf8");
        node.status({fill:"green", shape:"dot", text: lines.length + " radku zachovano"});
    }
} catch(e) {
    node.warn("Rotace log error: " + e.message);
}
return null;

// BALANCOVÁNÍ baterie — Pylontech 1×/30 dní, nabít 100% SOC, držet do vybalancování
var pBC=global.get("pat_block_charge")||false,cfg=global.get("fve_config")||{};
var _nibeEntity = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var _nibeKompresoryOn = _nibeEntity.state === "on";
var st=global.get("fve_status")||{};
var plan=global.get("fve_plan")||{},minSoc=cfg.min_soc||20,cSoc=st.battery_soc||50;
var maxG=cfg.max_spotreba_sit_w||22000,SAF=cfg.safety_margin_w||2000;
var cerp=msg.cerpadloTopi||false,autoC=msg.autoNabijeniAktivni||false,sauna=msg.saunaAktivni||false;
var ha=global.get("homeassistant.homeAssistant.states")||{};
var bI=parseFloat((ha["sensor.battery_dc_current"]||{}).state),mxV=parseFloat((ha["sensor.battery_max_cell_voltage"]||{}).state);
var mnV=parseFloat((ha["sensor.battery_min_cell_voltage"]||{}).state),bSP=parseFloat((ha["sensor.battery_soc_precise"]||{}).state);
if(isNaN(bSP))bSP=cSoc;
var inT=parseFloat((ha["sensor.hp2551ae_pro_v2_1_0_indoor_temperature"]||{}).state)||22;
var tgT=parseFloat((ha["input_number.nastavena_teplota_v_dome"]||{}).state)||23;
var pr=global.get("fve_prices_forecast")||[],hr=new Date().getHours(),LEVNA=cfg.prah_levna_energie||4,lvl=99;
for(var i=0;i<pr.length;i++)if(pr[i].hour===hr&&(pr[i].minute===0||pr[i].minute===undefined)){lvl=pr[i].levelCheapestHourBuy||99;break;}
var solS=(plan&&plan.config&&plan.config.solarStartHour)||9,solE=(plan&&plan.config&&plan.config.solarEndHour)||17;
var isSol=hr>=solS&&hr<solE;
var pvW=Math.round(parseFloat((ha["sensor.vyroba_fve"]||{}).state)||0);
var solPT=pvW>10?Math.max(50,pvW):0,gBias=cfg.setrit_grid_bias_w||150;
var sellP=99;for(var pi=0;pi<pr.length;pi++)if(pr[pi].hour===hr&&(pr[pi].minute===0||pr[pi].minute===undefined)){sellP=parseFloat(pr[pi].priceCZKhourProd)||99;break;}
var negSell=sellP<=0,shouldCh=isSol||lvl<=LEVNA;
var cons=[];if(cerp)cons.push("Top");if(autoC)cons.push("Auto");if(sauna)cons.push("Sauna");
var psp,maxFeed=cfg.max_feed_in_w||7600;
if(shouldCh){var _pvEB=global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']")||{};
var _pvWB=parseFloat(_pvEB.state)||0;
var _solPTB=_pvWB>10?Math.max(50,Math.round(_pvWB)):0;
var _nibeBlockB=_nibeKompresoryOn&&_pvWB<(cfg.topeni_solar_override_w||8000);
psp=(cerp||autoC)?maxG-SAF:-maxG;
msg.victron={power_set_point:psp,min_soc:minSoc,schedule_soc:100,schedule_charge_duration:86399,schedule_charge_day:7,
max_discharge_power:_nibeBlockB?_solPTB:-1,max_charge_power:pBC?0:-1,feedin_on:!negSell,max_feed_in_power:negSell?0:maxFeed,prevent_feedback:negSell?1:0};
}else{psp=gBias;msg.victron={power_set_point:gBias,min_soc:minSoc,schedule_soc:0,schedule_charge_duration:0,schedule_charge_day:-7,
max_discharge_power:solPT,max_charge_power:pBC?0:-1,feedin_on:!negSell,max_feed_in_power:negSell?0:maxFeed,prevent_feedback:negSell?1:0};}
// Balanced detection (20min continuous)
var cellD=(!isNaN(mxV)&&!isNaN(mnV))?mxV-mnV:1;
var isBalanced=bSP>=100&&Math.abs(bI)<0.5&&cellD<0.02;
var contMin=flow.get("bal_cont_min")||0;
if(isBalanced)contMin++;else contMin=0;flow.set("bal_cont_min",contMin);
var balanced20=contMin>=80;
// Force-stop
var fs=msg.forceStopBalancing||false;
var completed=global.get("balancing_completed")||false;
// Pump block: block if indoor temp is OK (>= target - 0.5)
var blockPump=inT>=(tgT-0.5);global.set("balancing_block_pump",blockPump);
// Solar dump: force excess solar into heaters when close to 100%
var solarDump=bSP>=98&&isSol;global.set("balancing_solar_dump",solarDump);
msg.balancing={current:isNaN(bI)?null:Math.round(bI*100)/100,cell_diff:Math.round(cellD*1000)/1000,
soc_precise:Math.round(bSP*10)/10,status:balanced20?"BALANCED":fs?"FORCE_STOP":"CHARGING",
cont_min:contMin,block_pump:blockPump,solar_dump:solarDump,consumers:cons.join(",")};
if(!completed&&(balanced20||fs)){global.set("balancing_completed",true);
var isFS=fs&&!balanced20;
msg.svcDatetime={action:"input_datetime.set_datetime",target:{entity_id:"input_datetime.last_pylontech_balanced"},data:{datetime:new Date().toISOString().slice(0,19).replace("T"," ")}};
msg.svcBoolean={action:"input_boolean."+(isFS?"turn_off":"turn_on"),target:{entity_id:"input_boolean.pylontech_balancing_ok"},data:{}};
node.status({fill:isFS?"red":"green",shape:"dot",text:(isFS?"FORCE_STOP":"BALANCED")+" "+Math.round(bSP)+"%"});
return[msg,{payload:msg.svcDatetime},{payload:msg.svcBoolean}];}
node.status({fill:"cyan",shape:"dot",text:"BAL SOC:"+Math.round(bSP)+"% I:"+(!isNaN(bI)?bI.toFixed(1):"?")+
"A ΔV:"+cellD.toFixed(3)+"V "+contMin+"/20min"+(cons.length>0?" ["+cons.join(",")+"]":"")});
return[msg,null,null];

// Check for pending opportunistic balancing result
var p=global.get("opp_bal_pending");
if(!p)return[null,null];
global.set("opp_bal_pending",null);
var _cfg=global.get("fve_config")||{};
var _fsh=_cfg.balancing_force_stop_hours||3;
// Law 12.5: ALWAYS store latest passive bal info for plan header
var _qual=p.durationH>=_fsh;
global.set("bal_header_info",{datetime:p.datetime,ok:p.ok,passive:true,durationH:p.durationH,maxIdleMin:p.maxIdleMin,qualifying:_qual});
// Law 12.5: ALWAYS update datetime entity (for header display)
var dtMsg={payload:{action:"input_datetime.set_datetime",target:{entity_id:"input_datetime.last_pylontech_balanced"},data:{datetime:p.datetime}}};
// Law 12.5: ALWAYS update boolean entity (for header OK/NOK)
var bMsg={payload:{action:"input_boolean."+(p.ok?"turn_on":"turn_off"),target:{entity_id:"input_boolean.pylontech_balancing_ok"},data:{}}};
if(_qual){
  global.set("last_qualifying_balance_ts",Date.now());
}else{
}
node.status({fill:p.ok?"green":"red",shape:"dot",text:(p.ok?"OK":"NOK")+" "+p.datetime+" "+p.durationH.toFixed(1)+"h"});
return[dtMsg,bMsg];

// §4.10 ZÁPORNÁ NÁKUPNÍ CENA — max odběr ze sítě.
// PSP-based control, max_discharge_power = -1 TRVALE (PowerAssist on, ŽÁDNÉ ESS7).
// Centrální arbitr zn_grid_guard (§4.10.5 vrstva 2) běží každou ~1 s a může PSP
// dále snížit (boost) při peaku — tato funkce stanovuje jen BASE PSP a Victron init.
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var currentSoc = status.battery_soc || 50;
var minSoc = config.min_soc || 20;

var prices = global.get("fve_prices_forecast") || [];
var hour = new Date().getHours();
var currentBuyPrice = 99, currentSellPrice = 0;
for (var i = 0; i < prices.length; i++) {
    if (prices[i].hour === hour && (prices[i].minute === 0 || prices[i].minute === undefined)) {
        currentBuyPrice = parseFloat(prices[i].priceCZKhourBuy) || 0;
        currentSellPrice = parseFloat(prices[i].priceCZKhourProd) || 0;
        break;
    }
}
var zakazPretoku = currentSellPrice <= 0;

var nibeEntity = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var nibePumpSt = (global.get("homeassistant.homeAssistant.states['sensor.nibe_aktualni_realny_stav']") || {}).state || "";
var nibeRunning = nibeEntity.state === "on" || (nibePumpSt.indexOf("Klidový") === -1 && nibePumpSt !== "");

var maxGrid = config.max_spotreba_sit_w || 22000;
var reserve = nibeRunning ? (config.zaporna_nibe_reserve_w || 5000) : (config.zaporna_flex_reserve_w || 3000);
var basePsp = maxGrid - reserve;
var pspMax = config.zaporna_psp_max_w || 18000;
basePsp = Math.min(basePsp, pspMax);

var guardBoost = parseInt(global.get("zn_psp_boost_w")) || 0;
var psp = Math.max(0, Math.min(basePsp - guardBoost, pspMax));

var maxFeedIn = config.max_feed_in_w || 7600;

msg.victron = {
    power_set_point: psp,
    min_soc: minSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    max_discharge_power: -1,
    max_charge_power: -1,
    feedin_on: !zakazPretoku,
    max_feed_in_power: zakazPretoku ? 0 : maxFeedIn,
    prevent_feedback: zakazPretoku ? 1 : 0
};
msg.mode = "zaporna_nakupni_cena";
msg.blockDischarge = false;

global.set("energy_arbiter", {
    mode: "zaporna_nakupni_cena",
    battery_charging: true,
    max_discharge_allowed: true,
    consumers_active: ["ZápornáNákup" + (zakazPretoku ? "+ZP" : "")],
    timestamp: Date.now()
});

var patEntity = global.get("homeassistant.homeAssistant.states['sensor.aktivni_faze_patron']") || {};
var patFaze = parseInt(patEntity.state) || 0;
var autoAmpsE = global.get("homeassistant.homeAssistant.states['sensor.charger_max_current_garage']") || {};
var autoAmps = parseFloat(autoAmpsE.state) || 0;
var autoCharging = ((global.get("homeassistant.homeAssistant.states['sensor.charger_state_garage']") || {}).state === "2");
var flexLoadW = patFaze * 3000 + (autoCharging ? autoAmps * 230 * 3 : 0);

var znState = global.get("zn_state") || "INIT";
var bumpTxt = guardBoost > 0 ? " BOOST -" + guardBoost + "W" : "";
var nibeLabel = nibeRunning ? " NIBE!" : "";
var zakazText = zakazPretoku ? " | ZP" : " | sell " + currentSellPrice.toFixed(2);
node.status({fill: "red", shape: "dot",
    text: "ZÁP " + currentBuyPrice.toFixed(2) + "Kč | PSP " + psp + "W (R" + reserve + bumpTxt + ") | " + znState + nibeLabel + zakazText + " | flex " + Math.round(flexLoadW/100)/10 + "kW | SOC " + currentSoc + "%"});

return msg;

// §4.10.5 vrstva 2 — CENTRÁLNÍ MANAGER JISTIČE (zn_grid_guard) v2 (4.6.2026).
// Tik = zaporna_buffer_interval_s (default 2 s, řízeno injectem zb_inject). Aktivní v módu zaporna_nakupni_cena.
// PRINCIP (user 4.6.2026): manager ZNÁ svůj buffer = baterie (PowerAssist vybíjení + možnost
//   shodit nabíjení) + solární přebytek. Buffer je PRIMÁRNÍ tlumič přechodných špiček
//   (i neviditelných zátěží jako vířivka). Patrony/auto/bojler se krátí JEN při SUSTAINED
//   peaku, stabilně po 1 kroku (anti-halucinace). Jistič (max_spotreba_sit_w) se NESMÍ překročit NIKDY.
// Vrstvy reakce na peak:
//   1) PSP boost → Victron zastaví nabíjení baterie / spustí PowerAssist (instant, zdarma).
//   2) sustained peak (>= effSustain tiků) → bojler OFF, auto -1A, patrony -1f / tik.
//   3) emergency (gridW > critW+emergMargin) → patrony 0, auto 6A, bojler OFF, boost x2 IHNED.
// Baterie: zdravá baterie (SOC > min+5) dostane effSustain tiků na absorpci špičky DŘÍV
//   než sáhneme na spotřebiče; vybitá baterie → krátíme hned (effSustain=1).
// max_discharge_power = -1 drží zaporna_nakup_logic (60s tick) per §4.10.5 vrstva 3.
// FIX 24.5.2026: zb_api_set smazán, wires -> shared_psp (mustache {{victron.power_set_point}}).

var arbiter = global.get("energy_arbiter") || {};
var liveMode = global.get("fve_current_mode") || "";
var active = (arbiter.mode === "zaporna_nakupni_cena") || (liveMode === "zaporna_nakupni_cena");
if (!active) {
    global.set("zn_state", null);
    global.set("zn_pat_max_floor", null);
    global.set("zn_auto_max_amps", null);
    global.set("zn_bojler_allowed", null);
    global.set("zn_psp_boost_w", null);
    context.set("state", "NORMAL");
    context.set("peak_ticks", 0);
    node.status({fill: "grey", shape: "ring", text: "idle (mód: " + (arbiter.mode || liveMode || "?") + ")"});
    return null;
}

var config  = global.get("fve_config") || {};
var critW   = config.zaporna_prah_critical_w   || 20000;
var safeW   = config.zaporna_prah_safe_w       || 19000;
var coolS   = config.zaporna_buffer_cooldown_s || 30;
var bumpW   = config.zaporna_psp_boost_w       || 2000;
var maxGrid = config.max_spotreba_sit_w        || 22000;
var maxAmp  = config.charger_max_amper         || 16;
var emergMargin  = config.zaporna_prah_emergency_w    || 1000;
var sustainTicks = config.zaporna_peak_sustain_ticks  || 2;
var batMaxDisW   = config.zaporna_bat_max_discharge_w || 12000;
var minSoc       = config.min_soc || 20;

var nibeRun = ((global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {}).state === "on");
var reserve = nibeRun ? (config.zaporna_nibe_reserve_w || 8000) : (config.zaporna_flex_reserve_w || 4000);
var pspMax  = config.zaporna_psp_max_w || 18000;
var basePsp = Math.min(maxGrid - reserve, pspMax);

var gridE = global.get("homeassistant.homeAssistant.states['sensor.spotreba_ze_site']") || {};
var gridW = parseFloat(gridE.state);
if (isNaN(gridW)) {
    node.status({fill: "grey", shape: "ring", text: "no grid sensor"});
    return null;
}

// --- BUFFER (baterie + solar): kolik W umíme okamžitě uvolnit, pro rozhodování/status ---
var soc = parseFloat((global.get("homeassistant.homeAssistant.states['sensor.battery_percent']") || {}).state);
if (isNaN(soc)) soc = 50;
var batChgW = parseFloat((global.get("homeassistant.homeAssistant.states['sensor.nabijeni_baterii_plus']") || {}).state);
if (isNaN(batChgW) || batChgW < 0) batChgW = 0;
var batDischAvail = (soc > minSoc) ? batMaxDisW : 0;
var bufferW = batChgW + batDischAvail;
var batDepleted = (soc <= minSoc + 5);
var effSustain = batDepleted ? 1 : sustainTicks;

var prevState = context.get("state") || "NORMAL";
var lastReleaseMs = context.get("last_release_ms") || 0;
var sinceReleaseS = (Date.now() - lastReleaseMs) / 1000;
var peakTicks = context.get("peak_ticks") || 0;

var newState = prevState;
if (gridW > critW) {
    newState = "PEAK";
    context.set("last_peak_ms", Date.now());
    peakTicks = peakTicks + 1;
} else if (gridW < safeW) {
    peakTicks = 0;
    if (prevState === "PEAK") {
        if (sinceReleaseS >= coolS) { newState = "NORMAL"; context.set("last_release_ms", Date.now()); }
    } else {
        newState = "NORMAL";
    }
} else {
    // hold zóna (safeW..critW): baterie tiše kryje, žádné cukání spotřebičů
    peakTicks = 0;
}
context.set("state", newState);
context.set("peak_ticks", peakTicks);

var patMaxFloor, autoMaxAmps, bojlerAllowed, pspBoost;
if (newState === "PEAK") {
    pspBoost = bumpW;
    var emerg = gridW > (critW + emergMargin);
    var curPat = parseInt((global.get("homeassistant.homeAssistant.states['sensor.aktivni_faze_patron']") || {}).state) || 0;
    var curAmps = parseInt((global.get("homeassistant.homeAssistant.states['sensor.charger_max_current_garage']") || {}).state) || maxAmp;
    if (emerg) {
        // EMERGENCY: nad critW+emergMargin → vše flexibilní OFF/min IHNED, dvojitý boost
        patMaxFloor = 0;
        autoMaxAmps = 6;
        bojlerAllowed = false;
        pspBoost = bumpW * 2;
    } else if (peakTicks < effSustain) {
        // Přechodná špička → baterie (PowerAssist přes PSP boost) ji tlumí, NEŠKRTIT (anti-halucinace)
        patMaxFloor = curPat;
        autoMaxAmps = curAmps;
        bojlerAllowed = true;
    } else {
        // SUSTAINED peak → stabilně krátit po 1: bojler OFF, auto -1A, patrony -1f
        patMaxFloor = Math.max(0, curPat - 1);
        autoMaxAmps = Math.max(6, curAmps - 1);
        bojlerAllowed = false;
    }
} else {
    pspBoost = 0;
    bojlerAllowed = true;
    patMaxFloor = 3;        // strop uvolněn; patrony korekce rampuje zpět sama (po 1f)
    autoMaxAmps = maxAmp;   // auto korekce rampuje zpět sama (po 1A)
}

global.set("zn_state", newState);
global.set("zn_pat_max_floor", patMaxFloor);
global.set("zn_auto_max_amps", autoMaxAmps);
global.set("zn_bojler_allowed", bojlerAllowed);
global.set("zn_psp_boost_w", pspBoost);
global.set("zn_grid_w", Math.round(gridW));
global.set("zn_buffer_w", Math.round(bufferW));
global.set("zn_last_tick_ms", Date.now());

var psp = Math.max(0, Math.min(basePsp - pspBoost, pspMax));

msg.victron = { power_set_point: psp };
msg.topic = "zn_grid_guard";
msg.zn = {
    state: newState, gridW: Math.round(gridW), psp: psp, pspBoost: pspBoost, buffer: Math.round(bufferW),
    patMaxFloor: patMaxFloor, autoMaxAmps: autoMaxAmps, bojlerAllowed: bojlerAllowed
};

var color = newState === "PEAK" ? "red" : "green";
var stateTxt = newState === "PEAK"
    ? ("PEAK +" + Math.round(gridW - critW) + "W t" + peakTicks + "/" + effSustain + " buf" + (Math.round(bufferW / 100) / 10) + "k → boost -" + pspBoost)
    : ("NORMAL");
node.status({fill: color, shape: "dot",
    text: stateTxt + " | grid " + Math.round(gridW) + "W → PSP " + psp + " | pat≤" + patMaxFloor + " auto≤" + autoMaxAmps + "A boj=" + (bojlerAllowed ? "ON" : "OFF")});

return msg;

// Parse Open-Meteo response, ulozi outdoor max 24h + min 48h do flow.
if (!msg.payload || !msg.payload.hourly || !msg.payload.hourly.temperature_2m) {
    node.status({fill: "red", shape: "ring", text: "Bad response"});
    return null;
}
var times = msg.payload.hourly.time;
var temps = msg.payload.hourly.temperature_2m;
var nowMs = Date.now();
var max24 = -100, min48 = 100, c24 = 0, c48 = 0;
for (var i = 0; i < times.length; i++) {
    var t = new Date(times[i] + ":00").getTime();
    var dh = (t - nowMs) / 3600000;
    if (dh < 0) continue;
    if (dh <= 24) { if (temps[i] > max24) max24 = temps[i]; c24++; }
    if (dh <= 48) { if (temps[i] < min48) min48 = temps[i]; c48++; }
    if (dh > 48) break;
}
if (c24 < 12 || c48 < 24) {
    node.status({fill: "yellow", shape: "ring", text: "Few data: 24h=" + c24 + " 48h=" + c48});
    return null;
}
flow.set("auto_rezim_outdoor_max_24h", max24);
flow.set("auto_rezim_outdoor_min_48h", min48);
flow.set("auto_rezim_outdoor_forecast_at", nowMs);
node.status({fill: "green", shape: "dot", text: "max24=" + max24.toFixed(1) + "° min48=" + min48.toFixed(1) + "°"});
return null;

// Auto LETO/ZIMA orchestrator — rozhodovaci logika (§19)
// Tick: 60s. Cte HA states + flow context.
// Vystup: msg.payload = "on" / "off" / null
var cfg = global.get("fve_config") || {};
var GAP        = cfg.topeni_auto_rezim_indoor_gap || 0.5;
var MIN_MIN    = cfg.topeni_auto_rezim_indoor_min_minut || 60;
var OD_NOW_Z   = cfg.topeni_auto_rezim_outdoor_now_zima || 12;
var OD_MAX_24H = cfg.topeni_auto_rezim_outdoor_max_24h || 10;
var OD_NOW_L   = cfg.topeni_auto_rezim_outdoor_now_leto || 14;
var OD_MIN_48H = cfg.topeni_auto_rezim_outdoor_min_48h || 10;
var MANUAL_H   = cfg.topeni_auto_rezim_manual_override_h || 12;
var ANTIFLAP_H = cfg.topeni_auto_rezim_anti_flap_h || 12;

function gS(id){return(global.get("homeassistant.homeAssistant.states['"+id+"']")||{}).state;}
function gF(id,d){var v=parseFloat(gS(id));return isNaN(v)?d:v;}
function gB(id){return gS(id) === "on";}

// 1) Hlavni vypinac
if (!gB("input_boolean.automaticke_prepinani_rezimu")) {
    node.status({fill: "grey", shape: "ring", text: "OFF (master)"});
    return null;
}

// 2) Forecast z flow context (alr_fn_parse vetev)
var fc = flow.get("auto_rezim_outdoor_forecast") || {};
var max24 = fc.max_24h;
var min48 = fc.min_48h;
var fcAge = fc.ts ? (Date.now() - fc.ts) / 60000 : 9999; // min
if (fcAge > 90) {
    node.status({fill: "yellow", shape: "ring", text: "forecast stale ("+fcAge.toFixed(0)+"min)"});
    return null;
}

// 3) Anti-flap
var lastChange = global.get("auto_rezim_last_change") || 0;
var sinceLastH = (Date.now() - lastChange) / 3600000;
if (sinceLastH < ANTIFLAP_H) {
    node.status({fill: "grey", shape: "dot",
        text: "anti-flap " + sinceLastH.toFixed(1) + "/" + ANTIFLAP_H + "h"});
    return null;
}

// 4) Manual override
var manualUntil = global.get("auto_rezim_manual_override_until") || 0;
if (Date.now() < manualUntil) {
    var leftH = (manualUntil - Date.now()) / 3600000;
    node.status({fill: "blue", shape: "dot",
        text: "manual " + leftH.toFixed(1) + "h left"});
    return null;
}

// 5) Cti HA states
var letni  = gB("input_boolean.letni_rezim");
var coolOn = gB("input_boolean.chlazeni"); // §8.0(B): chlazeni=ON blokuje LETO->ZIMA
var inT    = gF("sensor.hp2551ae_pro_v2_1_0_indoor_temperature", null);
var tgtT   = gF("input_number.nastavena_teplota_v_dome", null);
var outNow = gF("sensor.hp2551ae_pro_v2_1_0_outdoor_temperature", null);
if (outNow === null || isNaN(outNow)) outNow = gF("sensor.nibe_venkovni_teplota", null);

if (inT === null || tgtT === null || outNow === null) {
    node.status({fill: "red", shape: "ring",
        text: "missing T (in="+inT+", tgt="+tgtT+", out="+outNow+")"});
    return null;
}

// 6) Indoor sustain logic
var below = inT < (tgtT - GAP);
var above = inT >= tgtT;

if (letni && below) {
    var since = global.get("auto_rezim_indoor_below_since") || 0;
    if (!since) {
        global.set("auto_rezim_indoor_below_since", Date.now());
        since = Date.now();
    }
    var minutesBelow = (Date.now() - since) / 60000;

    // §8.0 + §19 chlazeni guard: pokud user zapnul chlazeni, NEPREPINAT na zimu.
    // Chlazeni je vedoma volba uzivatele - NIBE chladi a indoor klesne pod target je ocekavany dusledek.
    if (coolOn) {
        node.status({fill: "blue", shape: "ring",
            text: "LETO: chlazeni ON, blokovano (in="+inT.toFixed(1)+", tgt="+tgtT.toFixed(1)+")"});
        return null;
    }

    if (minutesBelow >= MIN_MIN && outNow <= OD_NOW_Z && (max24 != null && max24 <= OD_MAX_24H)) {
        global.set("auto_rezim_expected_state", "off");
        global.set("auto_rezim_last_change", Date.now());
        global.set("auto_rezim_indoor_below_since", 0);
        node.status({fill: "red", shape: "dot",
            text: "→ ZIMA (in="+inT.toFixed(1)+"<"+(tgtT-GAP).toFixed(1)+", out="+outNow+", max24="+max24+")"});
        msg.payload = "off";
        return msg;
    }
    node.status({fill: "yellow", shape: "ring",
        text: "LETO: in="+inT.toFixed(1)+"<tgt-gap "+minutesBelow.toFixed(0)+"/"+MIN_MIN+"min, out="+outNow+", max24="+(max24!=null?max24:"?")});
    return null;
} else {
    global.set("auto_rezim_indoor_below_since", 0);
}

if (!letni && above) {
    if (outNow >= OD_NOW_L && (min48 != null && min48 >= OD_MIN_48H)) {
        global.set("auto_rezim_expected_state", "on");
        global.set("auto_rezim_last_change", Date.now());
        node.status({fill: "green", shape: "dot",
            text: "→ LETO (in="+inT.toFixed(1)+">="+tgtT.toFixed(1)+", out="+outNow+", min48="+min48+")"});
        msg.payload = "on";
        return msg;
    }
    node.status({fill: "yellow", shape: "ring",
        text: "ZIMA: in="+inT.toFixed(1)+">=tgt, out="+outNow+", min48="+(min48!=null?min48:"?")});
    return null;
}

// Idle - zadna podminka neaktivovala prepnuti
node.status({fill: "grey", shape: "ring",
    text: (letni?"LETO":"ZIMA")+" stable, in="+inT.toFixed(1)+"/"+tgtT.toFixed(1)+", out="+outNow+(coolOn?", cool ON":"")});
return null;

// Detekce manual override letni_rezim (§ 19).
// Orchestrator si pamatuje 'expected_state' (= co naposled sam nastavil).
// Kdyz realna zmena != expected → manual.
var cfg = global.get("fve_config") || {};
var MANUAL_H = cfg.topeni_auto_rezim_manual_override_h || 12;

var newState = msg.payload; // "on" / "off"
var expected = global.get("auto_rezim_expected_state");

if (expected && expected === newState) {
    // To jsme udelali my — clear expected, zadny override
    global.set("auto_rezim_expected_state", null);
    node.status({fill: "grey", shape: "ring", text: "auto change → " + newState});
    return null;
}

// Jinak je to manual
var untilMs = Date.now() + MANUAL_H * 3600000;
global.set("auto_rezim_manual_override_until", untilMs);
global.set("auto_rezim_indoor_below_since", 0);
node.status({fill: "blue", shape: "dot",
    text: "MANUAL → " + newState + " | respektuji " + MANUAL_H + "h"});
return null;

// === Mod PRODAT PREBYTEK (prodej do site MISTO nabijeni baterie) — MANUALNI ===
// Cil: solarni prebytek NEukladat do baterie, ale exportovat (prodat) do site.
//   power_set_point  = -maxFeedIn => VYNUCENY export do site (negativni grid setpoint).
//       FIX 26.6.2026: PSP=0 NEFUNGOVALO — ESS udrzoval grid=0 a solarni prebytek vrazel
//       do BATERIE (DC-coupled solar; max_charge_power=0 DC nabijeni nezablokuje). Negativni
//       setpoint stahne solar na AC/grid misto do baterie. (Stejny princip jako mod PRODAVAT.)
//   max_charge_power = 0  => doplnkove blokuje AC nabijeni.
//   max_discharge    = 0  => baterie se NEvybiji do site (exportuje se jen solarni prebytek).
// POJISTKA: pri zaporne/nulove vykupni cene NEEXPORTOVAT (feedin off, nabijeni povoleno).
// Aktivace: rucne pres input_select.fve_manual_mod = "prodavat_misto_nabijeni".
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var currentSoc = status.battery_soc || 50;
var minSoc = config.min_soc || 20;
var maxFeedIn = config.max_feed_in_w || 7600;

// NIBE blok vybijeni (stejny vzor jako ostatni mody)
var _nibeEntity = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var _nibeKompresoryOn = _nibeEntity.state === "on";
var pvFveEntity = global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']") || {};
var currentPvPower = parseFloat(pvFveEntity.state) || 0;
var solarPassthrough = currentPvPower > 10 ? Math.max(50, Math.round(currentPvPower)) : 0;
var _solOvr = config.topeni_solar_override_w || 8000;
var saunaAktivni = msg.saunaAktivni || false;
var blockDischarge = (_nibeKompresoryOn && currentPvPower < _solOvr) || saunaAktivni;

// Aktualni vykupni cena — pojistka proti exportu pri zaporne cene
var prices = global.get("fve_prices_forecast") || [];
var hour = new Date().getHours();
var sellPrice = 99;
for (var i = 0; i < prices.length; i++) {
    if (prices[i].hour === hour && (prices[i].minute === 0 || prices[i].minute === undefined)) {
        sellPrice = parseFloat(prices[i].priceCZKhourProd);
        if (isNaN(sellPrice)) sellPrice = 0;
        break;
    }
}

if (sellPrice <= 0) {
    // POJISTKA: zaporna/nulova vykupni cena -> NEEXPORTOVAT (jako zakaz_pretoku)
    msg.victron = {
        power_set_point: 0,
        min_soc: minSoc,
        schedule_soc: 0,
        schedule_charge_duration: 0,
        schedule_charge_day: -7,
        max_discharge_power: blockDischarge ? solarPassthrough : -1,
        max_charge_power: -1,
        feedin_on: false,
        max_feed_in_power: 0,
        prevent_feedback: 1
    };
    msg.mode = "prodavat_misto_nabijeni_stop";
    global.set("energy_arbiter", {
        mode: "prodavat_misto_nabijeni_stop", battery_charging: false,
        max_discharge_allowed: !blockDischarge, consumers_active: [], timestamp: Date.now()
    });
    node.status({ fill: "purple", shape: "dot", text: "STOP export — vykup " + sellPrice.toFixed(2) + " Kc <= 0 | SOC " + currentSoc + "%" });
    return msg;
}

// Normalni provoz modu: nenabijet baterii, prebytek exportovat
msg.victron = {
    power_set_point: -maxFeedIn,
    min_soc: minSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    max_discharge_power: 0,
    max_charge_power: 0,
    feedin_on: true,
    max_feed_in_power: maxFeedIn,
    prevent_feedback: 0
};
msg.mode = "prodavat_misto_nabijeni";
msg.feedInExcess = true;

var consumers = [];
if (msg.cerpadloTopi) consumers.push("Topeni");
if (saunaAktivni) consumers.push("Sauna");
if (msg.virivkaAktivni) consumers.push("Virivka");
if (msg.autoNabijeniAktivni) consumers.push("Auto");
global.set("energy_arbiter", {
    mode: "prodavat_misto_nabijeni", battery_charging: false, reserved_for_battery_w: 0,
    max_discharge_allowed: !blockDischarge, consumers_active: consumers, timestamp: Date.now()
});
node.status({ fill: "red", shape: "dot", text: "PRODAT PREBYTEK (export PSP=-" + maxFeedIn + "W, charge/disch=0) | vykup " + sellPrice.toFixed(2) + " Kc | SOC " + currentSoc + "%" });
return msg;
